/**
 * @fileoverview Swipe component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — effects, defaults, CSS classes, abbreviations
 *   helpers.js   — pure utility / computation functions
 *   view.js      — DOM construction, UI updates, visual effects
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/Swipe
 */

import { default as razyui } from '../../index.js';
import { sharedResizeObserver } from '../shared/SharedResizeObserver.js';

import { DEFAULTS, EFFECTS, PART }  from './constants.js';
import {
    resolveJITTokens, resolveEffect,
    getContainerSize, getPanelSize, getStepSize, getOffsetFor,
    cardComputeMeta, cardOffsetFor,
    snapComputePositions, snapOffsetFor, snapFindClosest,
    dotPositionClass, makeClone,
} from './helpers.js';
import {
    buildTrack, buildDots, buildButtons, createClones,
    updateDots, updateButtons, updatePanels, setSwipeProperty,
    trackSnapTo, applyDragOffset, silentReposition,
    cardLayoutPanels, cardSnapTo, cardApplyAnimations,
    snapApplyPosition, snapUpdatePanels,
    applyItemStyle, initFocus,
    cleanupPanels, cleanupFocus,
} from './view.js';
import {
    bindDrag, bindCardDrag, bindSnapDrag,
    bindWheel, bindSnapWheel,
    bindKeyboard, bindDotClick, bindButtonClicks, bindPerViewClick,
    bindFocusScroll,
} from './events.js';

// ── Helpers (internal) ──────────────────────────

const ARIA_SLIDE = 'Slide';
const ARIA_ITEM  = 'Item';
const ARIA_PAGE  = 'Page';

/**
 * Swipe — v2
 *
 * Snap-scrolling carousel / swiper for panels in a container.
 * Supports touch drag, mouse drag, and scroll-wheel gestures.
 * When displaced past a configurable threshold, snaps to the
 * next or previous panel with a smooth CSS transition.
 *
 * Features:
 *   - Horizontal or vertical direction
 *   - Touch + pointer drag with momentum
 *   - Wheel / scroll gesture support
 *   - Configurable snap threshold (0–1, default 0.4)
 *   - Dot / bullet indicators (optional)
 *   - Prev / next navigation buttons (optional)
 *   - Infinite loop mode with seamless wrap-around (clones)
 *   - Auto-play with pause-on-interaction
 *   - Peek — show partial adjacent panels with optional spacing
 *   - Transition effects — 'slide' | 'fade' | 'stack' | 'flip' | 'card' | function
 *   - Card mode — multi-column card carousel with per-card peek & animations
 *   - Focus mode — hijack page scroll while container is in viewport
 *   - CSS custom property --swipe on container (0-based index)
 *   - getControl() API
 *
 * Config:
 *   direction   — 'horizontal' (default) or 'vertical'
 *   threshold   — 0–1 fraction to trigger snap (default 0.4)
 *   duration    — snap animation ms (default 300)
 *   easing      — CSS easing name (default 'ease-out')
 *   loop        — infinite wrap around (default false)
 *   dots        — show dot indicators (default true)
 *   dotPosition — dot placement: 'top-left' | 'top-center' | 'top-right'
 *                 | 'middle-left' | 'middle-center' | 'middle-right'
 *                 | 'bottom-left' | 'bottom-center' | 'bottom-right'
 *                 | false (hide dots) — default 'bottom-center'
 *   buttons     — show prev/next arrows (default true)
 *   autoPlay    — ms interval, 0 = off (default 0)
 *   gap         — gap between panels: JIT token ('sm','md','lg','xl') or px number (default 0)
 *   peek        — adjacent panel reveal: JIT token or px number (default 0)
 *   peekGap     — spacing between peeked items: JIT token or px number (default 0)
 *   perView     — number of panels visible at once (default 1). When > 1, panels are
 *                 sized to fit that many in the viewport with `gap` spacing. Navigate
 *                 steps by 1 panel. Combine with `itemStyle` for emphasis effects.
 *   effect      — 'slide' | 'fade' | 'stack' | 'flip' | 'card' | fn (default 'slide')
 *   focus       — false | true (stick top) | 'center' | 'fullpage' (full viewport)
 *
 *   Card mode config (when effect: 'card'):
 *     columns       — number of visible cards per page (default 1)
 *     cardWidth     — fixed width per card: JIT token or px number, 0 = auto (default 0)
 *                     When set, columns is auto-calculated from container width.
 *                     Peek is auto-derived from remaining space.
 *     cardGap       — gap between cards: JIT token or px number (default 16)
 *     cardPeek      — adjacent peeked card reveal: JIT token or px number (default 0)
 *     cardSwipe     — 'page' = swipe full set | 'single' = swipe one card (default 'page')
 *     onCardMove    — fn(cardEl, {index, page, slot, progress}) — animation while moving
 *     onCardPeekIn  — fn(cardEl, {index, direction}) — animation for card peeking into view
 *     onCardPeekOut — fn(cardEl, {index, direction}) — animation for card peeking out of view
 *
 * Callbacks:
 *   onChange(index, element)
 *
 * HTML pattern:
 *   <div id="my-swipe">
 *     <div>Slide 1</div>
 *     <div>Slide 2</div>
 *     <div>Slide 3</div>
 *   </div>
 * 
 * @class Swipe
 */
const Swipe = class {

    // ── Private fields ──────────────────────────

    /** @type {HTMLElement} */
    #container   = null;
    /** @type {HTMLElement} */
    #track       = null;
    /** @type {HTMLElement[]} */
    #panels      = [];    // original panels only
    /** @type {Object} */
    #config      = {};
    /** @type {number} */
    #index       = 0;     // logical index (0 to count-1)
    /** @type {number} */
    #trackIndex  = 0;     // position in track (offset for clones)
    /** @type {number} */
    #count       = 0;
    /** @type {boolean} */
    #destroyed   = false;

    // Clone tracking (infinite loop)
    /** @type {HTMLElement[]} */
    #clones       = [];
    /** @type {boolean} */
    #hasClones    = false;
    /** @type {number|null} */
    #pendingReposition = null;

    // Drag state
    /** @type {boolean} */
    #dragging    = false;
    /** @type {number} */
    #startPos    = 0;
    /** @type {number} */
    #currentDelta = 0;
    /** @type {number} */
    #startTime   = 0;

    // Effect
    /** @type {Function|null} */
    #effect      = null;   // resolved effect function or null (= slide)
    /** @type {boolean} */
    #isSlide     = true;   // true when using default track-transform mode
    /** @type {boolean} */
    #isCard      = false;  // true when using card mode
    /** @type {boolean} */
    #isSnap      = false;  // true when using magnetic snap mode

    // Magnetic snap state
    /** @type {number} */
    #snapOffset    = 0;    // current scroll offset (px, negative = scrolled right/down)
    /** @type {number[]} */
    #snapPositions = [];   // center position of each panel relative to track start

    // Card mode state
    /** @type {number} */
    #cardPageIndex = 0;    // current page (group of columns)
    /** @type {number} */
    #cardPageCount = 0;    // total pages
    /** @type {number[]} */
    #cardPositions = [];   // computed left offset per card
    /** @type {number} */
    #cardCols     = 1;     // effective visible columns (auto-calculated when cardWidth is set)
    /** @type {number} */
    #cardStep     = 1;     // how many cards to advance per swipe (columns for 'page', 1 for 'single')

    // Per-item styling
    /** @type {Object|null} */
    #itemStyle   = null;   // parsed itemStyle config map

    // Focus mode
    /** @type {boolean} */
    #focusActive = false;  // currently hijacking scroll

    // UI elements
    /** @type {HTMLElement} */
    #dotsEl      = null;
    /** @type {HTMLElement} */
    #prevBtn     = null;
    /** @type {HTMLElement} */
    #nextBtn     = null;

    // Auto-play
    /** @type {number} */
    #autoTimer   = 0;

    // Event cleanup (AbortControllers + observers)
    /** @type {Object<string, AbortController>} */
    #acs         = {};     // named AbortControllers
    /** @type {Element|null} */
    #resizeObsEl = null;   // Element tracked by shared ResizeObserver
    /** @type {Object|null} */
    #focusRefs   = null;   // refs returned by initFocus()

    // ── Constructor ─────────────────────────────

    /**
     * Creates an instance of Swipe.
     * @param {string|HTMLElement} selector - The container element or selector.
     * @param {Object} [config={}] - Configuration options.
     */
    constructor(selector, config = {}) {
        const container = razyui.isStr(selector)
            ? razyui(selector)[0]
            : selector;
        if (!container) { console.warn('Swipe: element not found \u2192', selector); return; }

        this.#container = container;
        this.#config = { ...DEFAULTS, ...config };

        // ── Resolve JIT spacing tokens → numeric px for layout math ──
        resolveJITTokens(this.#config, razyui.JIT.TOKEN.spacePx);

        // Parse itemStyle config
        if (config.itemStyle && typeof config.itemStyle === 'object') {
            this.#itemStyle = config.itemStyle;
        }

        // Resolve effect
        const resolved = resolveEffect(this.#config.effect, razyui);
        this.#effect  = resolved.effect;
        this.#isSlide = resolved.isSlide;
        this.#isCard  = resolved.isCard;
        this.#isSnap  = resolved.isSnap;

        this.#init();
    }

    // ── Initialization ──────────────────────────

    /**
     * Initializes the Swipe component based on the configured effect.
     * @private
     */
    #init() {
        if (this.#isCard) {
            this.#initCard();
            return;
        }
        if (this.#isSnap) {
            this.#initSnap();
            return;
        }
        this.#initDefault();
    }

    // ═══════════════════════════════════════════════
    //  Card mode
    // ═══════════════════════════════════════════════

    /**
     * Initializes the Swipe component in card mode.
     * @private
     */
    #initCard() {
        const cfg = this.#config;
        const ct = this.#container;

        const $ct = razyui(ct);
        $ct.addClass('swipe swipe-h swipe-card');
    PART.ROOT.apply(ct);

        // Build track + panels
        const built = buildTrack(ct, 'swipe-track swipe-card-track', 'swipe-panel', 'swipe-card-panel');
        this.#track  = built.track;
        this.#panels = built.panels;
        this.#count  = built.count;

        // Compute layout
        this.#cardComputeMetaInternal();
        this.#cardPageIndex = 0;
        this.#cardPositions = cardLayoutPanels(
            this.#panels, cfg, ct.offsetWidth, this.#count, this.#cardCols, this.#track,
        );

        // Dots (positioned below the card area, outside the container)
        if (cfg.dots && cfg.dotPosition !== false && this.#cardPageCount > 1) {
            this.#dotsEl = buildDots(this.#cardPageCount, cfg.dotPosition, ARIA_PAGE, 'swipe-card-dots');
            $ct.after(this.#dotsEl);
            this.#acs.dots = bindDotClick(this.#dotsEl, idx => this.#cardGo(idx));
        }

        // Prev / Next buttons
        if (cfg.buttons && this.#cardPageCount > 1) {
            const btns = buildButtons();
            this.#prevBtn = btns.prevBtn;
            this.#nextBtn = btns.nextBtn;
            $ct.append(this.#prevBtn);
            $ct.append(this.#nextBtn);
            this.#acs.buttons = bindButtonClicks(this.#prevBtn, this.#nextBtn, {
                onPrev: () => this.prev(),
                onNext: () => this.next(),
            });
        }

        // Bind events
        this.#bindCardDragInternal();
        this.#bindWheelInternal();
        this.#acs.keyboard = bindKeyboard(ct, cfg, {
            isDestroyed: () => this.#destroyed,
            onPrev: () => this.prev(),
            onNext: () => this.next(),
            onGoFirst: () => this.go(0),
            onGoLast: () => this.go(this.#cardPageCount - 1),
        });

        // Initial state
        this.#cardUpdate(false);

        // Auto-play
        if (cfg.autoPlay > 0) this.#startAutoPlay();

        // Resize observer for responsive card sizing (shared pool)
        this.#resizeObsEl = ct;
        sharedResizeObserver.observe(ct, () => {
            if (this.#destroyed) return;
            const prevCols = this.#cardCols;
            this.#cardComputeMetaInternal();
            if (this.#cardPageIndex >= this.#cardPageCount) {
                this.#cardPageIndex = this.#cardPageCount - 1;
            }
            this.#cardPositions = cardLayoutPanels(
                this.#panels, cfg, ct.offsetWidth, this.#count, this.#cardCols, this.#track,
            );
            cardSnapTo(
                this.#track,
                cardOffsetFor(this.#cardPageIndex, cfg, ct.offsetWidth, this.#count,
                              this.#cardCols, this.#cardStep, razyui.clamp),
                cfg.duration, cfg.easing, false,
            );
            cardApplyAnimations(this.#panels, this.#cardPageIndex, cfg,
                this.#count, this.#cardCols, this.#cardStep, false, this);
            if (prevCols !== this.#cardCols) this.#cardRebuildDots();
        });
    }

    /**
     * Computes effective columns, step, and page count for card mode.
     * @private
     */
    #cardComputeMetaInternal() {
        const meta = cardComputeMeta(this.#config, this.#container.offsetWidth, this.#count);
        this.#cardCols     = meta.cardCols;
        this.#cardStep     = meta.cardStep;
        this.#cardPageCount = meta.cardPageCount;
    }

    /**
     * Rebuilds dots when page count changes (e.g. on resize with cardWidth).
     * @private
     */
    #cardRebuildDots() {
        if (!this.#config.dots) return;
        if (this.#acs.dots) { this.#acs.dots.abort(); this.#acs.dots = null; }
        if (this.#dotsEl) this.#dotsEl.remove();
        this.#dotsEl = null;
        if (this.#cardPageCount > 1) {
            this.#dotsEl = buildDots(this.#cardPageCount, this.#config.dotPosition, ARIA_PAGE, 'swipe-card-dots');
            razyui(this.#container).after(this.#dotsEl);
            this.#acs.dots = bindDotClick(this.#dotsEl, idx => this.#cardGo(idx));
        }
        this.#cardUpdateDots();
    }

    /**
     * Updates card dots only.
     * @private
     */
    #cardUpdateDots() {
        updateDots(this.#dotsEl, this.#cardPageIndex);
    }

    /**
     * Updates card dots, buttons, custom property, and applies animations.
     * @param {boolean} [animate=true] - Whether to animate the transition.
     * @private
     */
    #cardUpdate(animate = true) {
        const cfg = this.#config;
        const offset = cardOffsetFor(
            this.#cardPageIndex, cfg, this.#container.offsetWidth,
            this.#count, this.#cardCols, this.#cardStep, razyui.clamp,
        );
        cardSnapTo(this.#track, offset, cfg.duration, cfg.easing, animate);
        cardApplyAnimations(this.#panels, this.#cardPageIndex, cfg,
            this.#count, this.#cardCols, this.#cardStep, animate, this);

        // Custom property
        setSwipeProperty(this.#container, this.#cardPageIndex);

        // Dots
        this.#cardUpdateDots();

        // Button visibility
        updateButtons(this.#prevBtn, this.#nextBtn,
            this.#cardPageIndex, this.#cardPageCount - 1, cfg.loop);
    }

    /**
     * Navigates to a specific card page.
     * @param {number} pageIndex - The index of the page to navigate to.
     * @private
     */
    #cardGo(pageIndex) {
        if (this.#destroyed) return;
        if (this.#config.loop) {
            if (pageIndex < 0) pageIndex = this.#cardPageCount - 1;
            else if (pageIndex >= this.#cardPageCount) pageIndex = 0;
        } else {
            pageIndex = razyui.clamp(pageIndex, 0, this.#cardPageCount - 1);
        }
        this.#cardPageIndex = pageIndex;
        // Map page index to logical slide index (first card of the page)
        this.#index = pageIndex * this.#cardStep;
        this.#cardUpdate();
        this.#fireChange();
    }

    // ── Card drag ───────────────────────────────

    /**
     * Binds drag events for card mode.
     * @private
     */
    #bindCardDragInternal() {
        const cfg = this.#config;
        let startY = 0;
        let axisDecided = false;
        let isVertical = false;

        this.#acs.drag = bindCardDrag(this.#track, {
            onStart: (e) => {
                if (this.#destroyed) return;
                this.#stopAutoPlay();
                this.#dragging = true;
                this.#startPos = e.clientX ?? e.touches[0].clientX;
                startY = e.clientY ?? e.touches[0].clientY;
                this.#currentDelta = 0;
                this.#startTime = Date.now();
                axisDecided = false;
                isVertical = false;
                this.#track.css('transition', 'none');
                this.#panels.forEach(p => { razyui(p).css('transition', 'none'); });
                this.#track.addClass('is-dragging');
            },
            onMove: (e) => {
                if (!this.#dragging || isVertical) return;
                const pos = e.clientX ?? e.touches[0].clientX;
                this.#currentDelta = pos - this.#startPos;

                // On first significant move, decide axis
                if (!axisDecided) {
                    const posY = e.clientY ?? e.touches[0].clientY;
                    const absX = Math.abs(this.#currentDelta);
                    const absY = Math.abs(posY - startY);
                    if (absX < 5 && absY < 5) return;
                    axisDecided = true;
                    if (absY > absX) {
                        isVertical = true;
                        return;
                    }
                }

                const base = cardOffsetFor(
                    this.#cardPageIndex, cfg, this.#container.offsetWidth,
                    this.#count, this.#cardCols, this.#cardStep, razyui.clamp,
                );
                this.#track.css('transform', `translate3d(${base + this.#currentDelta}px, 0, 0)`);
                if (Math.abs(this.#currentDelta) > 5) e.preventDefault();
            },
            onEnd: () => {
                if (!this.#dragging) return;
                this.#dragging = false;
                this.#track.removeClass('is-dragging');

                if (isVertical) {
                    // Was a vertical scroll — snap back without page change
                    this.#cardGo(this.#cardPageIndex);
                    if (cfg.autoPlay > 0) this.#startAutoPlay();
                    return;
                }

                const containerW = this.#container.offsetWidth;
                const threshold = containerW * cfg.threshold;
                const elapsed = Date.now() - this.#startTime;
                const velocity = Math.abs(this.#currentDelta) / Math.max(elapsed, 1);
                let newPage = this.#cardPageIndex;
                if (Math.abs(this.#currentDelta) > threshold || velocity > 0.5) {
                    if (this.#currentDelta < 0) newPage++;
                    else newPage--;
                }
                this.#cardGo(newPage);
                if (cfg.autoPlay > 0) this.#startAutoPlay();
            },
        });
    }

    // ═══════════════════════════════════════════════
    //  Magnetic Snap mode
    // ═══════════════════════════════════════════════

    /**
     * Initializes the Swipe component in magnetic snap mode.
     * @private
     */
    #initSnap() {
        const cfg = this.#config;
        const ct = this.#container;
        const isH = cfg.direction === 'horizontal';

        const $ct = razyui(ct);
        $ct.addClass(`swipe ${isH ? 'swipe-h' : 'swipe-v'} swipe-snap`);
    PART.ROOT.apply(ct);

        // Build track + panels
        const built = buildTrack(ct, 'swipe-track swipe-snap-track', 'swipe-panel');
        this.#track  = built.track;
        this.#panels = built.panels;
        this.#count  = built.count;

        // Apply gap to track
        const gap = cfg.gap || 0;
        if (gap) this.#track.css('gap', gap + 'px');

        // Compute panel center positions
        this.#snapPositions = snapComputePositions(this.#panels, cfg.direction, gap);

        // Initial snap to index 0
        this.#index = 0;
        this.#snapToInternal(this.#index, false);

        // Dots
        if (cfg.dots && cfg.dotPosition !== false && this.#count > 1) {
            this.#dotsEl = buildDots(this.#count, cfg.dotPosition, ARIA_ITEM, 'swipe-snap-dots');
            $ct.append(this.#dotsEl);
            this.#acs.dots = bindDotClick(this.#dotsEl, idx => this.go(idx));
        }

        // Buttons
        if (cfg.buttons && this.#count > 1) {
            const btns = buildButtons();
            this.#prevBtn = btns.prevBtn;
            this.#nextBtn = btns.nextBtn;
            $ct.append(this.#prevBtn);
            $ct.append(this.#nextBtn);
            this.#acs.buttons = bindButtonClicks(this.#prevBtn, this.#nextBtn, {
                onPrev: () => this.prev(),
                onNext: () => this.next(),
            });
        }

        // Drag events
        this.#bindSnapDragInternal();

        // Wheel events
        this.#acs.wheel = bindSnapWheel(ct, cfg, {
            isDestroyed: () => this.#destroyed,
            onStopAuto: () => this.#stopAutoPlay(),
            onNext: () => this.next(),
            onPrev: () => this.prev(),
            onStartAuto: () => { if (cfg.autoPlay > 0) this.#startAutoPlay(); },
        });

        // Keyboard
        this.#acs.keyboard = bindKeyboard(ct, cfg, {
            isDestroyed: () => this.#destroyed,
            onPrev: () => this.prev(),
            onNext: () => this.next(),
            onGoFirst: () => this.go(0),
            onGoLast: () => this.go(this.#count - 1),
        });

        // Update dots/buttons
        this.#snapUpdateUI();

        // Auto-play
        if (cfg.autoPlay > 0) this.#startAutoPlay();

        // Resize observer to recompute positions (shared pool)
        this.#resizeObsEl = ct;
        sharedResizeObserver.observe(ct, () => {
            if (this.#destroyed) return;
            this.#snapPositions = snapComputePositions(this.#panels, cfg.direction, cfg.gap || 0);
            this.#snapToInternal(this.#index, false);
        });
    }

    /**
     * Snaps the track to center on `index`.
     * @param {number} index - The index to snap to.
     * @param {boolean} [animate=true] - Whether to animate the transition.
     * @private
     */
    #snapToInternal(index, animate = true) {
        const cfg = this.#config;
        const isH = cfg.direction === 'horizontal';
        index = razyui.clamp(index, 0, this.#count - 1);
        this.#index = index;

        const containerSz = getContainerSize(this.#container, cfg.direction);
        const offset = snapOffsetFor(index, containerSz, this.#snapPositions);
        this.#snapOffset = offset;

        snapApplyPosition(this.#track, offset, isH, cfg.duration, cfg.easing, animate);
        snapUpdatePanels(this.#panels, index);
        setSwipeProperty(this.#container, index);
        this.#snapUpdateUI();
        applyItemStyle(this.#itemStyle, this.#panels, index,
            this.#count, cfg.loop, this.#clones, this.#hasClones);
    }

    /**
     * Updates dots and buttons for snap mode.
     * @private
     */
    #snapUpdateUI() {
        updateDots(this.#dotsEl, this.#index);
        updateButtons(this.#prevBtn, this.#nextBtn,
            this.#index, this.#count - 1, this.#config.loop);
    }

    /**
     * Binds drag events for snap mode.
     * @private
     */
    #bindSnapDragInternal() {
        const cfg = this.#config;
        const isH = cfg.direction === 'horizontal';

        this.#acs.drag = bindSnapDrag(this.#track, {
            onStart: (e) => {
                if (this.#destroyed) return;
                this.#stopAutoPlay();
                this.#dragging = true;
                this.#startPos = isH
                    ? (e.clientX ?? e.touches[0].clientX)
                    : (e.clientY ?? e.touches[0].clientY);
                this.#currentDelta = 0;
                this.#startTime = Date.now();
                this.#track.css('transition', 'none');
                this.#track.addClass('is-dragging');
            },
            onMove: (e) => {
                if (!this.#dragging) return;
                const pos = isH
                    ? (e.clientX ?? e.touches[0].clientX)
                    : (e.clientY ?? e.touches[0].clientY);
                this.#currentDelta = pos - this.#startPos;
                const newOffset = this.#snapOffset + this.#currentDelta;
                this.#track.css('transform', isH
                    ? `translate3d(${newOffset}px, 0, 0)`
                    : `translate3d(0, ${newOffset}px, 0)`);
                if (Math.abs(this.#currentDelta) > 5) e.preventDefault();
            },
            onEnd: () => {
                if (!this.#dragging) return;
                this.#dragging = false;
                this.#track.removeClass('is-dragging');

                const containerSz = getContainerSize(this.#container, cfg.direction);
                const finalOffset = this.#snapOffset + this.#currentDelta;
                const closest = snapFindClosest(finalOffset, containerSz, this.#snapPositions);
                const oldIndex = this.#index;
                this.#snapToInternal(closest, true);
                if (closest !== oldIndex) this.#fireChange();
                if (cfg.autoPlay > 0) this.#startAutoPlay();
            },
        });
    }

    // ═══════════════════════════════════════════════
    //  Default mode
    // ═══════════════════════════════════════════════

    /**
     * Initializes the Swipe component in default mode.
     * @private
     */
    #initDefault() {
        const cfg = this.#config;
        const ct = this.#container;
        const isH = cfg.direction === 'horizontal';

        const $ct = razyui(ct);
        $ct.addClass(`swipe ${isH ? 'swipe-h' : 'swipe-v'}`);
    PART.ROOT.apply(ct);

        // Non-slide effects need stacked layout
        if (!this.#isSlide) {
            $ct.addClass('swipe-effect');
        }

        // Build track + panels
        const built = buildTrack(ct, 'swipe-track', 'swipe-panel');
        this.#track  = built.track;
        this.#panels = built.panels;
        this.#count  = built.count;

        // Gap: for slide mode, apply combined gap + peekGap to the track
        if (this.#isSlide) {
            const trackGap = cfg.gap + cfg.peekGap;
            if (trackGap) this.#track.css('gap', trackGap + 'px');
        }

        // Apply per-view or peek sizing to panels
        if (cfg.perView > 1 && this.#isSlide) {
            const totalGap = (cfg.perView - 1) * cfg.gap;
            const basis = `calc((100% - ${totalGap}px) / ${cfg.perView})`;
            this.#panels.forEach(p => { razyui(p).css('flex', `0 0 ${basis}`); });
        } else if (cfg.peek > 0 && this.#isSlide) {
            const totalInset = cfg.peek * 2 + cfg.peekGap * 2;
            const basis = `calc(100% - ${totalInset}px)`;
            this.#panels.forEach(p => { razyui(p).css('flex', `0 0 ${basis}`); });
        }

        // Stamp duration/easing on panels for effect use
        this.#panels.forEach(p => {
            p._swipeDuration = cfg.duration;
            p._swipeEasing = cfg.easing;
        });

        // Create sentinel clones for seamless infinite loop (slide mode only)
        // Skip clones when perView >= count (all panels visible, nothing to scroll)
        if (cfg.loop && this.#count > 1 && this.#isSlide && !(cfg.perView >= this.#count)) {
            this.#clones = createClones(this.#track, this.#panels, el => makeClone(el, cfg));
            this.#hasClones = true;
        }

        // Dots
        if (cfg.dots && cfg.dotPosition !== false && this.#count > 1) {
            this.#dotsEl = buildDots(this.#count, cfg.dotPosition, ARIA_SLIDE);
            $ct.append(this.#dotsEl);
            this.#acs.dots = bindDotClick(this.#dotsEl, idx => this.go(idx));
        }

        // Prev / Next buttons
        if (cfg.buttons && this.#count > 1) {
            const btns = buildButtons();
            this.#prevBtn = btns.prevBtn;
            this.#nextBtn = btns.nextBtn;
            $ct.append(this.#prevBtn);
            $ct.append(this.#nextBtn);
            this.#acs.buttons = bindButtonClicks(this.#prevBtn, this.#nextBtn, {
                onPrev: () => this.prev(),
                onNext: () => this.next(),
            });
        }

        // Bind events
        this.#bindDragInternal();
        this.#bindWheelInternal();
        this.#acs.keyboard = bindKeyboard(ct, cfg, {
            isDestroyed: () => this.#destroyed,
            onPrev: () => this.prev(),
            onNext: () => this.next(),
            onGoFirst: () => this.go(0),
            onGoLast: () => this.go(this.#count - 1),
        });

        // Set initial track position
        this.#trackIndex = this.#hasClones ? 1 : 0;
        this.#update(false);

        // Defer itemStyle transitions so the initial positioning doesn't animate.
        if (this.#itemStyle) {
            requestAnimationFrame(() => {
                if (this.#destroyed) return;
                const props = new Set();
                for (const rule of Object.values(this.#itemStyle)) {
                    if (rule && typeof rule === 'object') {
                        for (const key of Object.keys(rule)) props.add(key);
                    }
                }
                if (props.size) {
                    const trans = [...props].map(p => `${p} ${cfg.duration}ms ${cfg.easing}`).join(', ');
                    this.#panels.forEach(p => { razyui(p).css('transition', trans); });
                    if (this.#hasClones && this.#clones) {
                        this.#clones.forEach(c => { razyui(c).css('transition', trans); });
                    }
                }
            });
        }

        // perView click-to-select: clicking a panel makes it active
        if (cfg.perView >= this.#count) {
            this.#acs.perViewClick = bindPerViewClick(this.#panels, i => {
                if (this.#index !== i) this.go(i);
            });
        }

        // Auto-play
        if (cfg.autoPlay > 0) this.#startAutoPlay();

        // Focus mode
        if (cfg.focus !== false) this.#initFocusInternal();
    }

    // ── Drag (pointer / touch) ──────────────────

    /**
     * Binds drag events for default mode.
     * @private
     */
    #bindDragInternal() {
        const cfg = this.#config;
        const isH = cfg.direction === 'horizontal';

        this.#acs.drag = bindDrag(this.#track, {
            onStart: (e) => {
                if (this.#destroyed) return;
                if (!this.#isSlide) return;
                if (cfg.perView >= this.#count) return;
                this.#stopAutoPlay();
                this.#flushReposition();
                this.#dragging = true;
                this.#startPos = isH ? (e.clientX ?? e.touches[0].clientX)
                                     : (e.clientY ?? e.touches[0].clientY);
                this.#currentDelta = 0;
                this.#startTime = Date.now();
                this.#track.css('transition', 'none');
                this.#track.addClass('is-dragging');
            },
            onMove: (e) => {
                if (!this.#dragging) return;
                const pos = isH ? (e.clientX ?? e.touches[0].clientX)
                                : (e.clientY ?? e.touches[0].clientY);
                this.#currentDelta = pos - this.#startPos;
                const base = getOffsetFor(this.#trackIndex, cfg, this.#stepSize(), this.#count);
                applyDragOffset(this.#track, base, this.#currentDelta, isH);
                if (Math.abs(this.#currentDelta) > 5) e.preventDefault();
            },
            onEnd: () => {
                if (!this.#dragging) return;
                this.#dragging = false;
                this.#track.removeClass('is-dragging');
                this.#settle();
                if (cfg.autoPlay > 0) this.#startAutoPlay();
            },
        });
    }

    // ── Wheel ───────────────────────────────────

    /**
     * Binds wheel events for default mode.
     * @private
     */
    #bindWheelInternal() {
        // Focus mode relies on native page scroll — don't intercept wheel
        if (this.#config.focus !== false) return;

        this.#acs.wheel = bindWheel(this.#container, this.#config, {
            isDestroyed: () => this.#destroyed,
            onStopAuto: () => this.#stopAutoPlay(),
            onNext: () => this.next(),
            onPrev: () => this.prev(),
            onStartAuto: () => { if (this.#config.autoPlay > 0) this.#startAutoPlay(); },
            getPanelSize: () => this.#panelSize(),
        });
    }

    // ── Focus mode (scroll hijack) ──────────────

    /**
     * Initializes focus mode (scroll hijacking).
     * @private
     */
    #initFocusInternal() {
        this.#focusRefs = initFocus(
            this.#container, this.#config, this.#count,
            (targetIndex) => {
                if (targetIndex !== this.#index) {
                    this.#goInternal(targetIndex);
                }
            },
            razyui.clamp,
        );
        // Bind window scroll/resize for focus mode
        this.#focusRefs.ac = bindFocusScroll(
            this.#focusRefs.onScroll,
            this.#focusRefs.onResize,
        );
    }

    // ── Clone management for infinite loop ──────

    // (clones are created via createClones() + makeClone() from submodules)

    // ── Size helpers ────────────────────────────

    /**
     * Gets the container size based on direction.
     * @returns {number} The container size in pixels.
     * @private
     */
    #containerSize() {
        return getContainerSize(this.#container, this.#config.direction);
    }

    /**
     * Gets the panel size based on container size and config.
     * @returns {number} The panel size in pixels.
     * @private
     */
    #panelSize() {
        return getPanelSize(this.#containerSize(), this.#config);
    }

    /**
     * Gets the step size based on panel size and config.
     * @returns {number} The step size in pixels.
     * @private
     */
    #stepSize() {
        return getStepSize(this.#panelSize(), this.#config);
    }

    // ── Settle after drag/wheel ─────────────────

    /**
     * Settles the swipe position after a drag or wheel event.
     * @private
     */
    #settle() {
        const size = this.#panelSize();
        const threshold = size * this.#config.threshold;
        const elapsed = Date.now() - this.#startTime;
        const velocity = Math.abs(this.#currentDelta) / Math.max(elapsed, 1);

        let newIndex = this.#index;
        if (Math.abs(this.#currentDelta) > threshold || velocity > 0.5) {
            if (this.#currentDelta < 0) newIndex++;
            else newIndex--;
        }

        this.go(newIndex);
    }

    // ── Silent reposition (infinite loop) ───────

    /**
     * Silently repositions the track for infinite loop wrap-around.
     * @param {number} trackIdx - The track index to reposition to.
     * @private
     */
    #silentRepositionInternal(trackIdx) {
        const isH = this.#config.direction === 'horizontal';
        const target = getOffsetFor(trackIdx, this.#config, this.#stepSize(), this.#count);
        silentReposition(this.#track, target, isH);
        this.#trackIndex = trackIdx;
    }

    /**
     * Schedules a silent reposition for infinite loop wrap-around.
     * @param {number} targetTrackIdx - The target track index.
     * @private
     */
    #scheduleReposition(targetTrackIdx) {
        if (this.#pendingReposition) {
            clearTimeout(this.#pendingReposition.timer);
        }
        const timer = setTimeout(() => {
            this.#pendingReposition = null;
            this.#silentRepositionInternal(targetTrackIdx);
        }, this.#config.duration + 20);
        this.#pendingReposition = { timer, targetTrackIdx };
    }

    /**
     * Flushes any pending silent reposition immediately.
     * @private
     */
    #flushReposition() {
        if (!this.#pendingReposition) return;
        const { timer, targetTrackIdx } = this.#pendingReposition;
        clearTimeout(timer);
        this.#pendingReposition = null;
        this.#silentRepositionInternal(targetTrackIdx);
    }

    // ── Update dots, buttons, panels, custom property ──

    /**
     * Updates dots, buttons, panels, and custom properties.
     * @param {boolean} [animate=true] - Whether to animate the transition.
     * @private
     */
    #update(animate = true) {
        const cfg = this.#config;
        const isH = cfg.direction === 'horizontal';

        // Track snap (slide mode)
        if (this.#isSlide) {
            const target = getOffsetFor(this.#trackIndex, cfg, this.#stepSize(), this.#count);
            trackSnapTo(this.#track, target, isH, cfg.duration, cfg.easing, animate);
        }

        // Effect (fade / stack / flip / custom)
        if (this.#effect) {
            this.#effect(this.#panels, this.#index, cfg.direction, this.#container, cfg, animate);
        }

        // Custom property
        setSwipeProperty(this.#container, this.#index);

        // Dots
        updateDots(this.#dotsEl, this.#index);

        // Button visibility
        updateButtons(this.#prevBtn, this.#nextBtn,
            this.#index, this.#count - 1, cfg.loop);

        // Panels
        updatePanels(this.#panels, this.#index);

        // Per-item styling
        applyItemStyle(this.#itemStyle, this.#panels, this.#index,
            this.#count, cfg.loop, this.#clones, this.#hasClones);
    }

    // ── Auto-play ───────────────────────────────

    /**
     * Starts auto-play.
     * @private
     */
    #startAutoPlay() {
        this.#stopAutoPlay();
        this.#autoTimer = setInterval(() => this.next(), this.#config.autoPlay);
    }

    /**
     * Stops auto-play.
     * @private
     */
    #stopAutoPlay() {
        if (this.#autoTimer) { clearInterval(this.#autoTimer); this.#autoTimer = 0; }
    }

    // ── Change callback ─────────────────────────

    /**
     * Fires the onChange callback.
     * @private
     */
    #fireChange() {
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange(this.#index, this.#panels[this.#index]);
        }
    }

    // ── Public API ──────────────────────────────

    /**
     * Navigates to a specific index (or page in card mode).
     * @param {number} index - The index or page to navigate to.
     */
    go(index) {
        if (this.#destroyed) return;

        // Card mode: index is page index
        if (this.#isCard) {
            this.#cardGo(index);
            return;
        }

        // Snap mode: snap to center
        if (this.#isSnap) {
            index = razyui.clamp(index, 0, this.#count - 1);
            const old = this.#index;
            this.#snapToInternal(index, true);
            if (index !== old) this.#fireChange();
            return;
        }

        // Flush any pending clone-reposition first
        this.#flushReposition();

        // perView >= count: all panels visible, just cycle index
        if (this.#config.perView >= this.#count) {
            if (this.#config.loop) {
                index = ((index % this.#count) + this.#count) % this.#count;
            } else {
                index = razyui.clamp(index, 0, this.#count - 1);
            }
            this.#index = index;
            this.#trackIndex = index;
            this.#update();
            this.#fireChange();
            return;
        }

        if (this.#config.loop && this.#hasClones) {
            if (index < 0) {
                // Going before first → animate to prepended clone
                this.#index = this.#count - 1;
                this.#trackIndex = 0;
                this.#update();
                this.#scheduleReposition(this.#count);
                this.#fireChange();
                return;
            }
            if (index >= this.#count) {
                // Going past last → animate to appended clone
                this.#index = 0;
                this.#trackIndex = this.#count + 1;
                this.#update();
                this.#scheduleReposition(1);
                this.#fireChange();
                return;
            }
            // Normal navigation within bounds
            this.#index = index;
            this.#trackIndex = index + 1;
        } else {
            // Non-loop: clamp
            index = razyui.clamp(index, 0, this.#count - 1);
            this.#index = index;
            this.#trackIndex = index;
        }

        this.#update();
        this.#fireChange();
    }

    /**
     * Internal go — skips flushReposition (used by focus scroll).
     * @param {number} index - The index to navigate to.
     * @private
     */
    #goInternal(index) {
        index = razyui.clamp(index, 0, this.#count - 1);
        this.#index = index;
        this.#trackIndex = this.#hasClones ? index + 1 : index;
        this.#update();
        this.#fireChange();
    }

    /**
     * Goes to the next panel (or page in card mode).
     */
    next() {
        if (this.#isCard) { this.#cardGo(this.#cardPageIndex + 1); return; }
        this.go(this.#index + 1);
    }

    /**
     * Goes to the previous panel (or page in card mode).
     */
    prev() {
        if (this.#isCard) { this.#cardGo(this.#cardPageIndex - 1); return; }
        this.go(this.#index - 1);
    }

    /**
     * Gets the controller object for the Swipe instance.
     * @returns {Object} The controller object.
     */
    getControl() {
        const self = this;
        return {
            get index() { return self.#isCard ? self.#cardPageIndex : self.#index; },
            set index(i) { self.go(i); },
            get count() { return self.#isCard ? self.#cardPageCount : self.#count; },
            get element() { return self.#container; },
            get pageIndex() { return self.#cardPageIndex; },
            get pageCount() { return self.#cardPageCount; },
            get autoPlay() { return self.#config.autoPlay; },
            set autoPlay(v) { self.#stopAutoPlay(); self.#config.autoPlay = Number(v) || 0; if (self.#config.autoPlay > 0) self.#startAutoPlay(); },
            get loop() { return self.#config.loop; },
            set loop(v) { self.#config.loop = !!v; },
            get perView() { return self.#config.perView; },
            set perView(v) { self.#config.perView = Number(v) || 1; },
            get gap() { return self.#config.gap; },
            set gap(v) { self.#config.gap = Number(v) || 0; },

            go:   (i) => self.go(i),
            next: () => self.next(),
            prev: () => self.prev(),

            /** Pause auto-play */
            pause: () => { self.#stopAutoPlay(); },

            /** Resume auto-play */
            resume: () => {
                if (self.#config.autoPlay > 0) self.#startAutoPlay();
            },

            destroy: () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Destroys the Swipe instance, cleaning up DOM and events.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#stopAutoPlay();
        this.#flushReposition();

        // Abort all event listeners via AbortControllers
        for (const ac of Object.values(this.#acs)) {
            if (ac && typeof ac.abort === 'function') ac.abort();
        }
        this.#acs = {};

        // Resize observer
        if (this.#resizeObsEl) {
            sharedResizeObserver.unobserve(this.#resizeObsEl);
            this.#resizeObsEl = null;
        }

        // Focus mode cleanup
        if (this.#focusRefs) {
            if (this.#focusRefs.ac) this.#focusRefs.ac.abort();
            if (this.#focusRefs.wrapper) {
                cleanupFocus(this.#container, this.#focusRefs.wrapper, this.#focusRefs.overflowOverrides);
            }
            this.#focusRefs = null;
        }

        // Remove clones
        this.#clones.forEach(c => c.remove());
        this.#clones = [];

        // Clean up DOM classes
        const $ct = razyui(this.#container);
        $ct.removeClass('swipe swipe-h swipe-v swipe-effect swipe-card swipe-snap');
        $ct.css('--swipe', '');
        $ct.removeAttr('tabindex');

        // Remove added elements
        if (this.#dotsEl) this.#dotsEl.remove();
        if (this.#prevBtn) this.#prevBtn.remove();
        if (this.#nextBtn) this.#nextBtn.remove();

        // Unwrap track → move panels back to container
        cleanupPanels(this.#panels, this.#container, this.#track);
    }
};

export default Swipe;
