/**
 * @fileoverview Swipe component definition for JIT pipeline.
 *
 * @module module/Swipe.def
 */

import razyui from '../index.js';
import { PART } from './Swipe/constants.js';

/**
 * The definition object for the Swipe component.
 * Contains metadata, tokens, states, templates, variants, and attribute mappings.
 *
 * @type {Object}
 */
export const SwipeDef = {
    name: 'Swipe',
    tag: 'rui-swipe',

    tokens: {
        prefix: 'sw',
        tokens: {
            'dots-gap':       { ref: 'spacing.2',           description: 'Dots gap' },
            'dots-padding':   { value: '0.5rem 0',         description: 'Dots padding' },
            'dots-offset':    { ref: 'spacing.2',           description: 'Dots offset' },
            'accent':         { ref: 'color.accent',        description: 'Accent / active dot' },
            'bg':             { ref: 'color.bg',            description: 'Background' },
            'bg-hover':       { ref: 'color.bg-hover',      description: 'Hover background' },
            'border':         { ref: 'color.border',        description: 'Border color' },
            'border-strong':  { ref: 'color.border-strong', description: 'Strong border' },
            'radius-lg':      { ref: 'radius.lg',           description: 'Arrow button radius' },
            'shadow-sm':      { ref: 'shadow.sm',           description: 'Arrow button shadow' },
            'text':           { ref: 'color.text',          description: 'Text / arrow color' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle:      { on: { DRAG_START: 'dragging', AUTO_PLAY: 'playing' } },
            dragging:  { on: { DRAG_END: 'idle' } },
            playing:   { on: { PAUSE: 'idle', DRAG_START: 'dragging' } },
        },
        effects: {
            dragging(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-dragging');
            },
            'dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-dragging');
            },
        },
    },

    template: {
        slots: {
            root:    { element: 'div', classes: ['swipe'] },
            track:   { element: 'div', classes: ['swipe-track'] },
            slide:   { element: 'div', classes: ['swipe-slide'] },
            dots:    { element: 'div', classes: ['swipe-dots'] },
            dot:     { element: 'button', classes: ['swipe-dot'] },
            arrow:   { element: 'button', classes: ['swipe-arrow'] },
        },
    },

    variants: {
        peek: { description: 'Peek mode showing adjacent slides' },
    },

    observedAttrs: ['auto-play', 'loop', 'per-view', 'gap'],
    attrMap: {
        'auto-play': 'autoPlay',
        loop: 'loop',
        'per-view': 'perView',
        gap: 'gap',
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.TRACK]: PART.TRACK,
        [PART.PANEL]: PART.PANEL,
        [PART.DOTS]: PART.DOTS,
        [PART.DOT]: PART.DOT,
        [PART.BTN]: PART.BTN,
        [PART.FOCUS_WRAPPER]: PART.FOCUS_WRAPPER,
        [PART.FOCUS_FULLBLEED]: PART.FOCUS_FULLBLEED,
        [PART.CARD_TRACK]: PART.CARD_TRACK,
        [PART.CARD_PANEL]: PART.CARD_PANEL,
        [PART.CARD_DOTS]: PART.CARD_DOTS,
        [PART.SNAP_TRACK]: PART.SNAP_TRACK,
        [PART.SNAP_DOTS]: PART.SNAP_DOTS,
    },

    styles: {},  /* All styles expressed via JIT */
};

export default SwipeDef;
